INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('春节', '全国', '春节', '农历正月初一，中国民间最盛大、最热闹的传统节日，又称过年。民间习惯贴剪纸、贴年画、贴春联、贴福字，除夕夜守岁、放爆竹，互相走访拜年。2006年列入第一批国家级非物质文化遗产名录。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('元宵节', '全国', '元宵节', '农历正月十五，又称上元节、灯节。民间风俗有扎彩灯、猜灯谜、耍龙灯、舞狮子、踩高跷、划旱船、吃元宵、放风筝等。2008年列入第二批国家级非物质文化遗产名录。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('清明节', '全国', '清明节', '公历4月5日前后，农历二十四节气之一。人们有祭祖、扫墓、踏青之俗。清明节与春节、端午节、中秋节并称为中国四大传统节日。2006年列入第一批国家级非物质文化遗产名录。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('端午节', '全国', '端午节', '农历五月初五，又称端阳节、龙舟节。家家户户吃粽子，南方有赛龙舟等习俗。纪念爱国诗人屈原。2006年列入第一批国家级非物质文化遗产名录，2009年入选世界非物质文化遗产。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('七夕节', '全国', '七夕节', '农历七月初七，传说是牛郎织女天河相会的日子，又称乞巧节、女儿节。过去姑娘们在这一天会穿针乞巧、拜织女，是中国传统节日中最具浪漫色彩的节日。2006年列入第一批国家级非物质文化遗产名录。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('中秋节', '全国', '中秋节', '农历八月十五，民间有祭月、赏月、吃月饼、饮桂花酒之俗，象征团圆。与春节、端午节、清明节并称为中国四大传统节日。2006年列入第一批国家级非物质文化遗产名录。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('重阳节', '全国', '重阳节', '农历九月初九，习俗包括登高赏秋、喝菊花酒、吃重阳糕。当今重阳节日活动的两大主题是登高赏秋与感恩敬老。2006年列入第一批国家级非物质文化遗产名录。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('腊八节', '全国', '腊八节', '农历十二月初八，家家户户吃腊八粥，用五谷杂粮加各种干果、糖煮成的粥。是佛教节日，也是中国传统民俗节日。', '存续', '中国非物质文化遗产网/民俗资料', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('除夕', '全国', '春节', '农历腊月最后一天，是春节的前夜。全家团聚吃年夜饭，守岁迎新，放鞭炮驱邪避灾。与清明节、七月半、重阳节并称中国传统四大祭祖节日。', '存续', '中国非物质文化遗产网/民俗资料', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('冬至', '全国', '冬至', '二十四节气之一，北半球白昼最短的一天。民间有吃饺子、汤圆等习俗，寓意团圆。有冬至大如年的说法。', '存续', '中国非物质文化遗产网/民俗资料', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('立春', '全国', '立春', '二十四节气之首，标志着春季的开始。民间有咬春习俗，吃春饼、春卷等，寓意迎春接福。', '存续', '中国非物质文化遗产网/民俗资料', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('北京庙会', '北京', '春节', '北京春节期间的传统民俗活动，以地坛庙会、龙潭庙会最为著名。有耍杂技、唱大戏、卖年货、吃小吃等传统活动，是北京人过年的重要习俗。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('广东舞狮', '广东', '春节', '广东地区春节期间的传统表演艺术，舞狮者装扮成狮子，随着锣鼓声起舞，寓意驱邪避灾、招财进宝。有南狮、北狮之分，广东以醒狮最为著名。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('四川变脸', '四川', '其他民俗', '川剧表演的特技之一，演员在瞬间变换脸谱，展现人物内心情绪变化。是四川地区独特的传统表演艺术，也是中国传统戏曲文化的瑰宝。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('福建妈祖祭典', '福建', '祭祀', '福建沿海地区祭祀妈祖的传统典礼，妈祖被视为海上保护神。每年妈祖诞辰日举行盛大祭典，包括迎神、上香、献供、诵经等仪式，是闽南地区重要的民俗活动。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('陕西秦腔', '陕西', '其他民俗', '中国古老的戏剧之一，起源于陕西、甘肃一带，唱腔高亢激越，表演粗犷豪放。是西北地区重要的传统艺术形式，被誉为黄土高原的摇滚。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('云南傣族泼水节', '云南', '春节', '傣族传统节日，也是傣族新年，一般在公历4月中旬举行。人们用清水相互泼洒，祈求洗去过去一年的不顺，迎接新的一年。是傣族最盛大的节日。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('山东潍坊风筝', '山东', '清明节', '潍坊是中国风筝之都，清明时节放风筝是当地传统习俗。潍坊风筝以竹为骨、绢为面，造型多样，色彩鲜艳，每年举办国际风筝节。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('苏州端午习俗', '江苏', '端午节', '苏州地区独特的端午习俗，除了吃粽子、赛龙舟外，还有挂钟馗像、贴五毒符、饮雄黄酒、佩香囊等习俗。苏州是端午节纪念伍子胥的发源地。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('景德镇瓷业习俗', '江西', '其他民俗', '景德镇千年瓷都的传统行业习俗，包括瓷业祭祀、行规行约、技艺传承等。瓷工们在特定节日祭拜窑神，祈求烧制顺利，是独特的工业民俗文化遗产。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('河南登封中岳庙会', '河南', '庙会', '中岳庙是道教圣地，每年农历三月和十月举行庙会。有祭祀中岳大帝的仪式，还有物资交流、民间艺术表演等活动，是中原地区重要的传统庙会。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('湖南汨罗江龙舟习俗', '湖南', '端午节', '汨罗江是屈原投江的地方，当地端午节龙舟竞渡习俗历史悠久。龙舟赛前要举行祭龙仪式，船员们喝雄黄酒、系五彩丝，表达对屈原的纪念。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('广西壮族三月三', '广西', '其他民俗', '农历三月初三是壮族传统节日，又称歌圩节。青年男女对唱山歌、抛绣球、碰彩蛋，是壮族青年社交和择偶的重要场合，也是壮族文化的集中展示。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('浙江绍兴黄酒酿制习俗', '浙江', '其他民俗', '绍兴黄酒是中国最古老的酒类之一，酿制工艺复杂，需要经过浸米、蒸饭、落缸、发酵等多道工序。立冬是绍兴黄酒开酿的日子，有祭酒神、开酿仪式等传统习俗。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('山西寒食节', '山西', '清明节', '寒食节在清明节前一二日，禁火冷食，纪念介子推。山西介休是寒食节的发源地，当地有禁火、扫墓、荡秋千、蹴鞠等传统习俗。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('天津皇会', '天津', '祭祀', '天津妈祖祭祀活动，又称娘娘会，是天津地区盛大的民俗活动。有仪仗、法鼓、高跷、秧歌等多种民间花会表演，是天津传统文化的重要组成部分。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('贵州苗族姊妹节', '贵州', '其他民俗', '台江县苗族传统节日，被称为最古老的东方情人节。姑娘们会穿上盛装、戴上银饰，与小伙子们对歌、游方、吃姊妹饭，是苗族青年恋爱社交的节日。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('海南黎族三月三', '海南', '其他民俗', '黎族传统节日，黎语称孚念孚。男女青年会聚在山坡上对唱民歌、跳竹竿舞、寻找意中人。是黎族人民悼念祖先、喜庆新生、赞美生活的传统节日。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('湖北武当山庙会', '湖北', '庙会', '武当山是道教圣地，每年春节和三月三举行盛大庙会。有朝山进香、道教法会、民间杂技、物资交流等活动，是鄂西北地区重要的传统民俗活动。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('安徽黄山庙会', '安徽', '庙会', '黄山地区传统庙会活动，有祭祀山神、祈福许愿、民间文艺表演等。黄山不仅是自然景观，也是道教和佛教圣地，庙会融合了多种宗教和民俗元素。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('内蒙古那达慕大会', '内蒙古', '其他民俗', '蒙古族传统节日，每年七八月间举行，有赛马、摔跤、叼羊等体育活动。那达慕是蒙古语娱乐或游戏的意思，是蒙古族人民展示勇武和技艺的盛会。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('新疆古尔邦节', '新疆', '其他民俗', '回族、维吾尔族等信仰伊斯兰教民族的传统节日，又称宰牲节。节前打扫房屋、制作糕点，节日当天穆斯林沐浴后参加会礼，还有宰羊、赛马、摔跤等活动。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('四川彝族火把节', '四川', '其他民俗', '彝族最盛大的传统节日，一般在农历六月二十四举行。人们点燃火把在田间游走，祈求丰收、驱邪避灾。夜晚举行篝火晚会，青年男女载歌载舞。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('云南白族三月街', '云南', '其他民俗', '大理白族传统节日，又称观音市，每年农历三月十五至二十举行。是物资交流和民族文艺活动的盛会，有赛马、对歌、贸易等活动。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('甘肃兰州太平鼓', '甘肃', '春节', '兰州地区春节传统表演艺术，是一种带有浓郁西北风情的汉族民俗舞蹈。表演者手持太平鼓，边击边舞，气势磅礴，寓意天下太平、五谷丰登。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('吉林朝鲜族农乐舞', '吉林', '其他民俗', '朝鲜族传统舞蹈，源于农耕文化，表现农民劳动和丰收的喜悦。舞蹈节奏明快，动作优美，常在小农乐乐队伴奏下进行，是朝鲜族最具代表性的民间舞蹈。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('广东潮汕英歌舞', '广东', '春节', '潮汕地区传统民间舞蹈，表演者手持英歌槌，按照锣鼓节奏敲打，边舞边行。舞蹈融合了武术、戏剧元素，气势豪迈，是潮汕文化的重要代表。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('福建客家土楼营造技艺', '福建', '其他民俗', '福建客家人独特的建筑技艺，土楼以生土为主要建筑材料，建筑形式有圆楼、方楼、五凤楼等。土楼营造技艺体现了客家人聚族而居、防御外敌的智慧。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('山东胶东花饽饽', '山东', '春节', '胶东地区传统面食艺术，用面粉捏制各种造型的花饽饽，有龙凤、花卉、动物等造型。春节期间制作花饽饽寓意吉祥如意，是胶东地区重要的年俗。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('浙江龙泉青瓷烧制技艺', '浙江', '其他民俗', '龙泉青瓷是中国陶瓷史上烧制时间最长、影响最大的窑系之一，始于三国两晋，盛于南宋。青瓷以釉色青翠、造型典雅著称，有雨过天青云破处的美誉。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('江苏苏州评弹', '江苏', '其他民俗', '苏州地区传统曲艺形式，包括评话和弹词两种。评弹用苏州方言表演，说噱弹唱，故事情节生动，是江南水乡文化的重要代表。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('河北吴桥杂技', '河北', '其他民俗', '吴桥县是中国杂技之乡，杂技历史悠久，技艺精湛。吴桥杂技包括魔术、马戏、杂技等多种表演形式，被誉为世界杂技艺术的摇篮。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('湖北恩施摆手舞', '湖北', '其他民俗', '土家族传统舞蹈，摆手是土家语跳舞的意思。摆手舞动作古朴粗犷，多在祭祀祖先、庆祝丰收时跳，是土家族文化的重要组成部分。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('湖南花鼓戏', '湖南', '其他民俗', '湖南地方戏曲剧种，形成于清代，以长沙花鼓戏最为著名。花鼓戏表演生动活泼，唱腔优美动听，是湖湘文化的重要载体。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('四川自贡灯会', '四川', '元宵节', '自贡地区传统民俗活动，始于唐宋，盛于明清。自贡灯会规模宏大，灯组造型精美，集灯彩、灯雕、灯塑于一体，被誉为天下第一灯。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('云南纳西古乐', '云南', '其他民俗', '纳西族传统音乐，由白沙细乐和丽江古乐两部分组成。纳西古乐保留了大量唐宋元时期的音乐元素，被誉为音乐活化石。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('安徽黄梅戏', '安徽', '其他民俗', '安徽地方戏曲剧种，起源于湖北黄梅，发展于安徽安庆。黄梅戏唱腔淳朴流畅，表演质朴细腻，以《天仙配》《女驸马》等剧目闻名全国。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('河南豫剧', '河南', '其他民俗', '河南地方戏曲剧种，是中国五大戏曲剧种之一。豫剧唱腔高亢激昂，表演大气磅礴，有东方咏叹调之称，流行于河南及周边省份。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('辽宁海城高跷', '辽宁', '元宵节', '海城地区传统民间舞蹈，表演者脚踩高跷，扮成各种角色进行表演。海城高跷技艺高超，动作惊险，是东北地区最具代表性的高跷表演之一。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('黑龙江赫哲族鱼皮制作技艺', '黑龙江', '其他民俗', '赫哲族传统手工技艺，用鱼皮制作衣服、鞋子等生活用品。鱼皮衣轻便保暖，防水耐磨，是赫哲族适应寒冷地区渔猎生活的智慧结晶。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('广东粤剧', '广东', '其他民俗', '广东地方戏曲剧种，是中国五大戏曲剧种之一。粤剧唱腔优美，表演细腻，融合了唱、做、念、打等多种艺术形式，流行于广东及东南亚地区。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('江西赣南采茶戏', '江西', '其他民俗', '赣南地区传统戏曲剧种，源于茶农劳动生活。采茶戏表演轻松活泼，唱腔优美动听，具有浓郁的乡土气息，是赣南文化的重要代表。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('山西晋剧', '山西', '其他民俗', '山西地方戏曲剧种，又称中路梆子。晋剧唱腔高亢激越，表演粗犷豪放，是山西三大梆子剧种之一，流行于山西中北部地区。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('青海塔尔寺酥油花', '青海', '元宵节', '塔尔寺传统宗教艺术，用酥油捏制各种佛像、花卉、建筑等造型。酥油花色彩艳丽，造型精美，每年正月十五在塔尔寺展出，吸引众多信众和游客。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('西藏藏戏', '西藏', '其他民俗', '藏族传统戏曲，藏语称阿吉拉姆。藏戏历史悠久，表演形式独特，演员戴着面具表演，讲述佛经故事和历史传说，是藏族文化的瑰宝。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('宁夏回族花儿', '宁夏', '其他民俗', '回族传统民歌形式，花儿又称少年。花儿曲调高亢悠扬，歌词多表达爱情和生活中的情感，在西北地区广泛流传，被誉为西北之魂。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('四川糖画', '四川', '春节', '四川传统民间手工艺，用熔化的糖汁在石板上绘制各种图案。糖画艺人可以在几秒内画出龙、凤、花鸟等图案，深受儿童喜爱，是庙会常见的手工艺。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('北京景泰蓝', '北京', '其他民俗', '北京传统工艺品，又称铜胎掐丝珐琅。景泰蓝制作工艺复杂，包括制胎、掐丝、点蓝、烧蓝、磨光、镀金等多道工序，是宫廷艺术的代表。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('上海沪剧', '上海', '其他民俗', '上海地方戏曲剧种，源于上海浦东民歌。沪剧用上海方言演唱，表演生活化，擅长表现现代题材，是上海本土文化的重要代表。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('天津杨柳青年画', '天津', '春节', '天津传统民间艺术，与苏州桃花坞年画并称南桃北柳。杨柳青年画采用木版套印和手工彩绘相结合，题材多为吉祥喜庆内容，是春节装饰的重要元素。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-03T12:00:00Z');